INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('para Estados terceiros, de conduções à fronteira nos termos do artigo 147.º ou do apoio ao regresso voluntário nos termos do artigo 139.º, dão imediatamente origem à inserção de uma indicação para efeitos de recusa de entrada e de permanência no SII UCFE e no SIS devendo sempre acautelar-se o registo da data da sua execução ou do cumprimento do dever de regresso.
  2 - ...
